    replaced_mam_marks = _combining_marks_after(mam_text, replaced_mam_pos)
    replaced_qere_marks = _combining_marks_after(qere_text, replaced_qere_pos)
    next_mam_marks = _combining_marks_after(mam_text, next_mam_pos)
