def _is_xaser_malei_opcode_shape(
    opcodes: list[tuple[str, int, int, int, int]],
    skeleton_mam: str,
    skeleton_qere: str,
) -> bool:
    deleted_matres: list[str] = []
    inserted_matres: list[str] = []
    for tag, mam_start, mam_end, qere_start, qere_end in opcodes:
        if tag == "equal":
            continue
        if tag == "delete":
            deleted = skeleton_mam[mam_start:mam_end]
            if not deleted or not all(character in MATRES for character in deleted):
                return False
            deleted_matres.extend(deleted)
            continue
        if tag == "insert":
            inserted = skeleton_qere[qere_start:qere_end]
            if not inserted or not all(character in MATRES for character in inserted):
                return False
            inserted_matres.extend(inserted)
            continue
        if tag == "replace":
            deleted = skeleton_mam[mam_start:mam_end]
            inserted = skeleton_qere[qere_start:qere_end]
            if (
                not deleted
                or not inserted
                or not all(character in MATRES for character in deleted)
                or not all(character in MATRES for character in inserted)
            ):
                return False
            deleted_matres.extend(deleted)
            inserted_matres.extend(inserted)
            continue
        return False
    return sorted(deleted_matres) != sorted(inserted_matres)


def _skeleton_positions(text: str) -> list[int]:
    return [
        index
        for index, character in enumerate(text)
        if not unicodedata.combining(character)
    ]


def _strip_all_points(text: str) -> str:
    return "".join(
        character for character in text if not unicodedata.combining(character)
    )


def _combining_marks_after(text: str, position: int) -> list[str]:
    marks: list[str] = []
    for index in range(position + 1, len(text)):
        character = text[index]
        if not unicodedata.combining(character):
            break
        marks.append(character)
    return marks


def _preceding_letter_marks(text: str, position: int) -> list[str]:
    for index in range(position - 1, -1, -1):
        if text[index] in HEBREW_LETTERS:
            return _combining_marks_after(text, index)
    return []


def _primary_vowel_name(marks: list[str]) -> str | None:
    for mark in marks:
        name = MARK_NAMES.get(mark)
        if name is not None:
            return name
    return None


def _find_primary_vowel_mark(marks: list[str]) -> str | None:
    for mark in marks:
        if mark in MARK_NAMES:
            return mark
    return None


def _mater_spelling_suffix(
    *, text: str, skeleton_index: int, positions: list[int]
) -> str | None:
    character = text[positions[skeleton_index]]
    if character not in MATRES:
        return None
    marks = _combining_marks_after(text, positions[skeleton_index])
    previous_marks = _preceding_letter_marks(text, positions[skeleton_index])
    vowel_name = _vowel_name_for_mater(character, marks, previous_marks)
    if vowel_name is None:
        return MATER_NAMES[character]
    if vowel_name == "shuruq":
        return vowel_name
    return f"{vowel_name}-{MATER_NAMES[character]}"


def _vowel_name_for_mater(
    character: str, marks: list[str], previous_marks: list[str]
) -> str | None:
    if character == "ו":
        if HOLAM in marks:
            return MARK_NAMES[HOLAM]
        if DAGESH in marks:
            return "shuruq"
        if QAMATS in previous_marks:
            return MARK_NAMES[QAMATS]
        if QAMATS_QATAN in previous_marks:
            return MARK_NAMES[QAMATS_QATAN]
        return None
    if character == "י":
        if HIRIQ in marks:
            return MARK_NAMES[HIRIQ]
        if TSERE in marks:
            return MARK_NAMES[TSERE]
        if TSERE in previous_marks:
            return MARK_NAMES[TSERE]
        if HIRIQ in previous_marks:
            return MARK_NAMES[HIRIQ]
        if QAMATS in previous_marks:
            return MARK_NAMES[QAMATS]
        return None
    return None
